Below is a simplified Python-like pseudo-code illustrating 2PC between two databases (participants) and a coordinator:
python
class Coordinator:
    def __init__(self, participants):
        self.participants = participants

    def commit(self):
        # Phase 1: Prepare
        votes = []
        for p in self.participants:
            vote = p.prepare()
            votes.append(vote)
            if vote == "NO":
                self.abort()
                return

        # Phase 2: Commit
        for p in self.participants:
            p.commit()

    def abort(self):
        for p in self.participants:
            p.rollback()

class Participant:
    def prepare(self):
        # Check if transaction can be committed
        return "YES"  # or "NO"

    def commit(self):
        # Execute commit
        pass

    def rollback(self):
        # Revert changes
        pass

# Usage:
coordinator = Coordinator([Participant(), Participant()])
coordinator.commit()
